/**
 * 组装 Agent 入参：基于首帧/尾帧写丝滑运镜提示词
 * - 输出：firstUrl, lastUrl, agent_user_prompt
 */

function s(v){ return v == null ? '' : String(v); }
function safe(v){ return s(v).replace(/\r?\n/g, ' ').trim(); }

function getTmpUrl(nodeName) {
  try {
    const j = $(nodeName).first().json;
    return safe(j?.body?.data?.tmp_download_urls?.[0]?.tmp_download_url);
  } catch (e) {
    return '';
  }
}

const firstUrl =
  getTmpUrl('获取首帧图下载链接') ||
  getTmpUrl('获取首帧图下载链接0') ||
  getTmpUrl('获取首帧图下载链接1');

const lastUrl =
  getTmpUrl('获取尾帧图下载链接') ||
  getTmpUrl('获取尾帧图下载链接0') ||
  getTmpUrl('获取尾帧图下载链接1');

if (!firstUrl || !lastUrl) {
  throw new Error('prompt 为空且缺少首帧/尾帧下载链接，无法自动生成运镜提示词');
}

const agent_user_prompt =
  '以第一张图为首帧图，第二张图为尾帧图，写一个连接首尾丝滑过渡的AI运镜提示词。' +
  '要求：只输出提示词，不要解释；强调镜头运动/速度/景别变化/转场方式/光线连续性；适配 8 秒竖屏短视频；尽量写得像给视频模型的指令。';

return [{ json: { firstUrl, lastUrl, agent_user_prompt } }];

/**
 * 组装 Gemini generateContent 请求体
 * - 支持 n8n binary 为 filesystem-v2（落盘）时读取 Buffer 再转 base64
 * - 依赖：下载首帧图 outputPropertyName=first_image
 *        下载尾帧图 outputPropertyName=last_image
 */

const agent_user_prompt =
  '以第一张图为首帧图，第二张图为尾帧图，写一个连接首尾丝滑过渡的AI运镜提示词。' +
  '要求：只输出纯英文提示词，不要解释；强调镜头运动/速度/景别变化/转场方式/光线连续性；适配8秒竖屏短视频；尽量写得像给视频模型的指令。';

const items = $input.all();
if (!items.length) throw new Error('没有输入 item');

async function readB64(itemIndex, binaryKey) {
  const bin = items[itemIndex]?.binary?.[binaryKey];
  if (!bin) throw new Error(`缺少 binary.${binaryKey}（检查下载节点 outputPropertyName）`);

  const d = bin.data;
  if (d && typeof d === 'string' && d !== 'filesystem-v2' && !d.startsWith('filesystem:')) {
    return { b64: d, mime: bin.mimeType || 'image/jpeg' };
  }

  if (this?.helpers?.getBinaryDataBuffer) {
    const buf = await this.helpers.getBinaryDataBuffer(itemIndex, binaryKey);
    return { b64: buf.toString('base64'), mime: bin.mimeType || 'image/jpeg' };
  }

  throw new Error(
    `binary.${binaryKey} 是 filesystem-v2，但当前环境拿不到 helpers.getBinaryDataBuffer；` +
    `请确认这是 n8n Code 节点（不是表达式字段）并且允许使用 helpers。`
  );
}

const first = await readB64.call(this, 0, 'first_image');
const last  = await readB64.call(this, 0, 'last_image');

const gemini_body = {
  contents: [
    {
      role: 'user',
      parts: [
        { text: agent_user_prompt },
        { inline_data: { mime_type: first.mime, data: first.b64 } },
        { inline_data: { mime_type: last.mime,  data: last.b64  } }
      ]
    }
  ],
  generationConfig: {
    temperature: 0.4,
    maxOutputTokens: 8192
  }
};

return [{ json: { gemini_body } }];

/**
 * 从 Gemini generateContent 响应里提取文本
 */

const res = $input.first().json || {};
const root = res.data ?? res;

const parts = root?.candidates?.[0]?.content?.parts || [];
const text = parts.map(p => p?.text ?? '').join('').trim();

if (!text) {
  throw new Error('Gemini 未返回有效提示词：' + JSON.stringify(root).slice(0, 800));
}

return [{ json: { prompt_from_agent: text } }];

