/**
 * 准备视频参数-Veo3（云雾 /v1/video/create）
 * ✅ payload.model 原样透传
 * ✅ 兼容：只有首帧 / 首尾帧 / 无图
 * ✅ 关键：prompt 为空时，优先用 Agent 生成的 prompt
 * ✅ 关键：images 优先使用【云雾图床 URL】，避免 feishu internal 临时链接导致云雾抓取失败
 */

const payload = $('子流程入口-Veo3').first().json.body || {};

function s(v){ return v == null ? '' : String(v); }
const safe = (v) => s(v).replace(/\r?\n/g, ' ').trim();

function getTmpUrl(nodeName) {
  try {
    const j = $(nodeName).first().json;
    return safe(j?.body?.data?.tmp_download_urls?.[0]?.tmp_download_url);
  } catch (e) {
    return '';
  }
}

function getPicbedUrl(nodeName) {
  try {
    const j = $(nodeName).first().json;
    // 图床返回常见：{ url: '...' } 或 { data: { url: '...' } }
    return safe(j?.url || j?.data?.url || '');
  } catch (e) {
    return '';
  }
}

// ---- 必填上下文字段 ----
const record_id = safe(payload.record_id);
const app_token = safe(payload.app_token);
const table_id = safe(payload.table_id);
const tenant_access_token = safe(payload.tenant_access_token);
const api_key = safe(payload.api_key);
const workflow_id_for_credits = safe(payload.workflow_id_for_credits);

if (!record_id || !app_token || !table_id || !tenant_access_token || !api_key || !workflow_id_for_credits) {
  throw new Error('子流程入口缺少必要字段（record_id/app_token/table_id/tenant_access_token/api_key/workflow_id_for_credits）');
}

// ---- prompt：优先 Agent 覆盖，其次入参 prompt ----
let prompt = '';
try { prompt = safe($('提取Agent提示词').first().json.prompt_from_agent); } catch (e) {}
if (!prompt) prompt = safe(payload.prompt);

if (!prompt) {
  throw new Error('prompt 为空：且未生成 Agent prompt（检查 prompt是否为空 分支/Agent 调用）');
}

// ---- aspect_ratio ----
const aspect_ratio = safe(payload.aspect_ratio) || '9:16';

// ---- model：严格遵守入参（原样透传）----
const model = safe(payload.model) || 'veo3-fast';

// ---- 首/尾帧 URL：优先图床 ----
const firstUrl_picbed = getPicbedUrl('上传首帧到图床');
const lastUrl_picbed  = getPicbedUrl('上传尾帧到图床');

// ---- 兜底：如果图床没跑到（比如没上传首帧），再 fallback 到 feishu tmp（不推荐但可保底） ----
const firstUrl_tmp =
  getTmpUrl('获取首帧图下载链接') ||
  getTmpUrl('获取首帧图下载链接0') ||
  getTmpUrl('获取首帧图下载链接1');

const lastUrl_tmp =
  getTmpUrl('获取尾帧图下载链接') ||
  getTmpUrl('获取尾帧图下载链接0') ||
  getTmpUrl('获取尾帧图下载链接1');

const firstUrl = firstUrl_picbed || firstUrl_tmp;
const lastUrl  = lastUrl_picbed  || lastUrl_tmp;

let images;
if (firstUrl && lastUrl) images = [firstUrl, lastUrl];
else if (firstUrl) images = [firstUrl];

const requestBody = {
  model,
  prompt,
  ...(images?.length ? { images } : {}),
  enhance_prompt: payload.enhance_prompt ?? false,
  enable_upsample: payload.enable_upsample ?? true,
  aspect_ratio
};

return [{
  json: {
    requestBody,
    record_id,
    app_token,
    table_id,
    tenant_access_token,
    api_key,
    workflow_id_for_credits,
    debug: {
      prompt_from_input: safe(payload.prompt),
      prompt_from_agent: (() => { try { return safe($('提取Agent提示词').first().json.prompt_from_agent); } catch(e){ return '';} })(),
      model_from_input: safe(payload.model),
      model_used: model,
      aspect_ratio,
      images_count: images?.length || 0,
      firstUrl_picbed,
      lastUrl_picbed,
      firstUrl_tmp,
      lastUrl_tmp,
      firstUrl_used: firstUrl,
      lastUrl_used: lastUrl
    }
  }
}];

const res = $input.first().json || {};

const id = res.id || res.data?.id;
const status = res.status || res.data?.status || 'unknown';

if (!id) {
  throw new Error(`创建任务失败，响应里没有 id：${JSON.stringify(res).slice(0, 500)}`);
}

return [{
  json: {
    task_id: id,
    status
  }
}];

